import React, {
	useEffect,
	useState,
} from "react";


import {_monthNames } from "../stores/Utils";

import "./MonthPicker.css";
import { SvgIcon_Cmpt } from ".";


const Svg = SvgIcon_Cmpt();

const DropDwnPickerComponent = ({init, onSelect, list, lbl_empty, direction, background, color }) => {
	
	const [open, setOpen] = useState(false);
	const [show, setShow] = useState(false);
	const [showCO, setShowCO] = useState(false);


	const handleSelection = (v) => {
		handleClick(v);
		
	}



	const handleClick = (v) => {
		if(show){
			setShow(false)
			setShowCO(false)
			setTimeout(() => {
				setOpen(false);
				v && onSelect(v);
			}, 200);
		}else if(!show){
			setOpen(true)
			setTimeout(() => {
				setShow(true)
			}, 50);
			setTimeout(() => {
				setShowCO(true)
			}, 450);
		}
	};

	

	const handleClickOutSide = () => {
				
		if(open){
			setShow(false);
			setShowCO(false);
			setTimeout(() => {
				setOpen(false);
			}, 200);
		}
		
		
	}


	let labelInit = list.filter(e=>e.id===init)?.[0];

	let dir = direction || "left";

	let _style = {
		"--color-pck":color?color:null,
		"--backColor-pck":background?background:null
	}

	return (
		<div  id={`drpdwn_click_outside`} open={open} style={_style} >
			<div className={"filter_month_btn _dsplFlx"} onClick={handleClick}>
				<div className="lbl date" >
						{labelInit?.label || lbl_empty}
				</div>
				
					<Svg name={"arrow_drop_down"} color={"var(--color-pck)"}/>
				
			</div>
			
			{open?
			 <div className={"OpenBoxContainer"} style={background?{backgroundColor: background}:null} direction={`${dir}`}>
				<div  className={" monthList"} style={{}}>
					{list.map((elm, wwInd)=>{
						let mnt = elm.label;

						if(!mnt){
							return null;
						}
						return (
							<div 
								key={mnt + "_" +wwInd}  
								className={"filter_month_item _dsplFlx"} 
								onClick={()=>handleSelection(elm)}
							>
								<div className="lbl tr_bar_10" >
								
								</div>
								<div className="lbl tr_bar_70" >
									{mnt}
								</div>
								<div className="lbl tr_bar_20" >
									<div>
										<Svg name={init===elm.id?"success":null} color={"var(--color-pck)"}/>
									</div>
								</div>
							</div>
						)
					})}
				</div>
			</div>
			:null}
		
			
		</div>
		
	);
};

export default DropDwnPickerComponent;

